function solve(n: number): number {
    // Helper function to check if a number is a palindrome
    function isPalindrome(num: number): boolean {
        const str = num.toString();
        return str === str.split('').reverse().join('');
    }

    // Helper function to check if a number is a special number
    function isSpecial(num: number): boolean {
        const str = num.toString();
        const count: { [key: string]: number } = {};
        for (const ch of str) {
            const digit = parseInt(ch, 10);
            if (digit === 0) continue; // Skip zeros as they cannot appear exactly 0 times
            count[digit] = (count[digit] || 0) + 1;
        }
        for (const key in count) {
            if (count[key] !== parseInt(key, 10)) {
                return false;
            }
        }
        return true;
    }

    // Generate numbers greater than n and check for the smallest special number
    let result: number | null = null;
    for (let i = n + 1; i <= 1000000000000000; i++) {
        if (isPalindrome(i) && isSpecial(i)) {
            result = i;
            break;
        }
    }

    return result || 0;
}

